import {
    FrameworkConfiguration,
    FrameworkLifeCycles,
    LoadableApp,
    loadMicroApp,
    registerMicroApps,
    RegistrableApp
} from 'qiankun';
import { uniqBy } from 'lodash';
import { proxyConsole } from '../../logger';
import { SpotterMicroAppMountProps } from '../app-communication-protocol';
export type { MicroApp } from 'qiankun';

export function getDefaultAppLifeCycles<
    T extends SpotterMicroAppMountProps
>(): FrameworkLifeCycles<T> {
    return {
        beforeLoad: [
            (app, subWindow) => {
                proxyConsole(subWindow, app);

                console.log('[LifeCycle] before load %c%s', 'color: green;', app.name);
                return Promise.resolve();
            }
        ],
        beforeMount: [
            (app, subWindow) => {
                console.log('[LifeCycle] before mount %c%s', 'color: green;', app.name);
                // 添加子应用版本上报
                window?.__OSS_MONITOR_SDK_?.setConfig({
                    // api 日志丢失，只有pv perf health 上报成功
                    tag: subWindow?.__SPOTTER_APP_BOOT_DATA__?.version
                });
                return Promise.resolve();
            }
        ],
        afterUnmount: [
            (app) => {
                console.log('[LifeCycle] after unmount %c%s', 'color: green;', app.name);
                return Promise.resolve();
            }
        ]
    };
}

export function registerApps<T extends SpotterMicroAppMountProps>(
    microApps: RegistrableApp<T>[],
    {
        afterRegister,
        lifeCycles
    }: {
        afterRegister?: (uniqMircoApps: RegistrableApp<T>[]) => void;
        lifeCycles?: FrameworkLifeCycles<T>;
    }
) {
    const uniqMircoApps = uniqBy(microApps, 'name');
    registerMicroApps<T>(uniqMircoApps, {
        ...getDefaultAppLifeCycles<T>(),
        ...lifeCycles
    });
    afterRegister && afterRegister(uniqMircoApps);
}

export function loadApp<T extends SpotterMicroAppMountProps>(
    app: LoadableApp<T>,
    configuration: FrameworkConfiguration,
    lifeCycles?: FrameworkLifeCycles<T>
) {
    return loadMicroApp(app, configuration, {
        ...getDefaultAppLifeCycles<T>(),
        ...lifeCycles
    });
}
